        private void ChangeButton(object sender, EventArgs e)
        {
            Button btn = sender as Button;
            string coord = btn.Name;

            foreach (var list in colorMap.Values)
            {
                var item = list.Items.Cast<ListViewItem>()
                    .FirstOrDefault(i => i.Name == coord);

                if (item != null)
                {
                    list.Items.Remove(item);
                }
            }

            if (btn.BackColor == activeColor)
            {
                btn.BackColor = Color.White;
                return;
            }

            btn.BackColor = activeColor;

            var newItem = new ListViewItem(coord);
            newItem.Name = coord;
            colorMap[activeColor].Items.Add(newItem);
        }



