        private void ResetGrid(object sender, EventArgs e)
        {
            foreach (var list in colorMap.Values)
            {
                list.Items.Clear();
            }

            foreach (Control c in tableLayoutPanel1.Controls)
            {
                if (c is Button && Equals(c.Tag, "grid"))
